    }

    body {
      margin: 0;
      min-height: 100vh;
      display: grid;
      place-items: center;
      padding: 20px;
      font-family: Inter, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
      background:
        radial-gradient(circle at top, rgba(120, 240, 106, 0.1), transparent 32%),
        linear-gradient(180deg, #121820 0%, #0d1217 100%);
      color: var(--text);
    }

    .app {
      width: min(100%, 860px);
      display: grid;
