    }

    .hud,
    .controls {
      display: flex;
      align-items: center;
      justify-content: space-between;
      gap: 12px;
      flex-wrap: wrap;
      padding: 14px 16px;
      background: rgba(26, 34, 44, 0.92);
      border: 1px solid var(--panel-border);
      border-radius: var(--radius);
      box-shadow: var(--shadow);
    }

    .scoreboard {
      display: flex;
      gap: 16px;
      flex-wrap: wrap;
    }

    .metric {
      display: grid;
      gap: 2px;
    }

    .metric-label {
      font-size: 0.8rem;
      color: var(--muted);
      text-transform: uppercase;
    }

    .metric-value {
      font-size: 1.35rem;
      font-weight: 700;
      line-height: 1;
    }

    .status {
      color: var(--muted);
      font-size: 0.95rem;
      text-align: right;
    }

    .board-wrap {
      position: relative;
      width: var(--board);
      justify-self: center;
    }

    canvas {
      display: block;
      width: 100%;
      height: auto;
      background:
        linear-gradient(180deg, rgba(255, 255, 255, 0.02), rgba(255, 255, 255, 0)),
        #0d141a;
      border: 1px solid var(--panel-border);
      border-radius: var(--radius);
      box-shadow: var(--shadow);
      image-rendering: pixelated;
    }

    .overlay {
      position: absolute;
      inset: 0;
      display: grid;
      place-items: center;
      padding: 24px;
      border-radius: var(--radius);
      background: rgba(9, 13, 18, 0.72);
      opacity: 0;
      pointer-events: none;
      transition: opacity 160ms ease;
    }

    .overlay.is-visible {
      opacity: 1;
      pointer-events: auto;
