<body>
  <main class="app">
    <section class="hud" aria-label="Game status">
      <div class="scoreboard">
        <div class="metric">
          <span class="metric-label">Score</span>
          <span class="metric-value" id="score">0</span>
        </div>
        <div class="metric">
          <span class="metric-label">Best</span>
          <span class="metric-value" id="best-score">0</span>
        </div>
      </div>
      <div class="status" id="status-text">Press an arrow key to start.</div>
    </section>

    <section class="board-wrap" aria-label="Snake board">
      <canvas id="board" width="600" height="600" aria-label="Snake game board"></canvas>
      <div class="overlay is-visible" id="overlay" aria-live="polite">
        <div class="overlay-card">
          <h1 id="overlay-title">Snake</h1>
          <p id="overlay-text">Use the arrow keys to move. Eat food, grow longer, and avoid walls and yourself.</p>
          <button id="restart-button" type="button">Start Game</button>
        </div>
      </div>
    </section>

    <section class="controls" aria-label="Instructions">
      <div><strong>Controls:</strong> Arrow keys to steer.</div>
      <div><strong>Restart:</strong> Use the button or press space after game over.</div>
    </section>
  </main>

  <script>
    const board = document.getElementById("board");
    const ctx = board.getContext("2d");
    const scoreEl = document.getElementById("score");
    const bestScoreEl = document.getElementById("best-score");
    const statusTextEl = document.getElementById("status-text");
    const overlayEl = document.getElementById("overlay");
    const overlayTitleEl = document.getElementById("overlay-title");
    const overlayTextEl = document.getElementById("overlay-text");
    const restartButton = document.getElementById("restart-button");

    const gridSize = 20;
    const tileCount = 20;
    const boardSize = board.width;
    const tileSize = boardSize / tileCount;
    const moveInterval = 120;
    const directions = {
      ArrowUp: { x: 0, y: -1 },
      ArrowDown: { x: 0, y: 1 },
      ArrowLeft: { x: -1, y: 0 },
      ArrowRight: { x: 1, y: 0 }
    };

    let snake;
    let direction;
    let nextDirection;
    let food;
    let score;
    let bestScore = Number(localStorage.getItem("snake-best-score") || 0);
    let lastTick = 0;
    let started = false;
    let gameOver = false;

    function resetGame() {
      snake = [
        { x: 9, y: 10 },
        { x: 8, y: 10 },
        { x: 7, y: 10 }
      ];
      direction = { x: 1, y: 0 };
      nextDirection = { x: 1, y: 0 };
      food = spawnFood();
      score = 0;
      lastTick = 0;
      started = false;
      gameOver = false;
      updateScore();
      statusTextEl.textContent = "Press an arrow key to start.";
      hideOverlay();
      draw();
    }

    function spawnFood() {
      while (true) {
        const candidate = {
          x: Math.floor(Math.random() * tileCount),
          y: Math.floor(Math.random() * tileCount)
        };

        if (!snake.some((segment) => segment.x === candidate.x && segment.y === candidate.y)) {
          return candidate;
        }
      }
    }

    function updateScore() {
      scoreEl.textContent = String(score);
      bestScoreEl.textContent = String(bestScore);
    }

    function showOverlay(title, text, buttonText) {
      overlayTitleEl.textContent = title;
      overlayTextEl.textContent = text;
      restartButton.textContent = buttonText;
      overlayEl.classList.add("is-visible");
    }

    function hideOverlay() {
      overlayEl.classList.remove("is-visible");
    }

    function setGameOver() {
      gameOver = true;
      statusTextEl.innerHTML = '<span class="game-over">Game over.</span> Press space or restart.';
      showOverlay("Game Over", `Final score: ${score}. Try to beat ${bestScore}.`, "Play Again");
    }

    function handleDirection(key) {
      const proposed = directions[key];
      if (!proposed || gameOver) {
        return;
      }

      const reversing =
        snake.length > 1 &&
        proposed.x === -direction.x &&
        proposed.y === -direction.y;

      if (reversing) {
        return;
      }

      nextDirection = proposed;
      if (!started) {
        started = true;
        statusTextEl.textContent = "Game in progress.";
        hideOverlay();
      }
    }

    function update() {
      if (!started || gameOver) {
        return;
      }

      direction = nextDirection;
      const head = snake[0];
      const nextHead = {
        x: head.x + direction.x,
        y: head.y + direction.y
      };

      const hitWall =
        nextHead.x < 0 ||
        nextHead.x >= tileCount ||
        nextHead.y < 0 ||
        nextHead.y >= tileCount;

      const hitSelf = snake.some(
        (segment) => segment.x === nextHead.x && segment.y === nextHead.y
      );

      if (hitWall || hitSelf) {
        setGameOver();
        return;
      }

      snake.unshift(nextHead);

      if (nextHead.x === food.x && nextHead.y === food.y) {
        score += 10;
        if (score > bestScore) {
          bestScore = score;
          localStorage.setItem("snake-best-score", String(bestScore));
        }
        updateScore();
        food = spawnFood();
      } else {
        snake.pop();
      }
    }

    function drawGrid() {
      ctx.strokeStyle = "rgba(255, 255, 255, 0.05)";
      ctx.lineWidth = 1;

      for (let i = 1; i < tileCount; i += 1) {
        const offset = i * tileSize;
        ctx.beginPath();
        ctx.moveTo(offset, 0);
        ctx.lineTo(offset, boardSize);
        ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(0, offset);
        ctx.lineTo(boardSize, offset);
        ctx.stroke();
      }
    }

    function drawFood() {
      const padding = tileSize * 0.18;
      ctx.fillStyle = "#ff8f4d";
      ctx.fillRect(
        food.x * tileSize + padding,
        food.y * tileSize + padding,
        tileSize - padding * 2,
        tileSize - padding * 2
      );
    }

    function drawSnake() {
      snake.forEach((segment, index) => {
        const padding = index === 0 ? tileSize * 0.08 : tileSize * 0.14;
        ctx.fillStyle = index === 0 ? "#95ff89" : "#59d64c";
        ctx.fillRect(
          segment.x * tileSize + padding,
          segment.y * tileSize + padding,
          tileSize - padding * 2,
          tileSize - padding * 2
        );
      });
    }

    function draw() {
      ctx.clearRect(0, 0, boardSize, boardSize);
      drawGrid();
      drawFood();
      drawSnake();
    }

    function frame(timestamp) {
      if (!lastTick) {
        lastTick = timestamp;
      }

      if (timestamp - lastTick >= moveInterval) {
        lastTick = timestamp;
        update();
        draw();
      }

      requestAnimationFrame(frame);
    }

    document.addEventListener("keydown", (event) => {
      if (event.key in directions) {
        event.preventDefault();
        handleDirection(event.key);
        return;
      }

      if ((event.key === " " || event.key === "Enter") && gameOver) {
        event.preventDefault();
        resetGame();
        showOverlay("Snake", "Use the arrow keys to move. Eat food, grow longer, and avoid walls and yourself.", "Start Game");
      }
    });

    restartButton.addEventListener("click", () => {
      resetGame();
      showOverlay("Snake", "Use the arrow keys to move. Eat food, grow longer, and avoid walls and yourself.", "Start Game");
      restartButton.blur();
    });

    bestScoreEl.textContent = String(bestScore);
    showOverlay("Snake", "Use the arrow keys to move. Eat food, grow longer, and avoid walls and yourself.", "Start Game");
    resetGame();
    requestAnimationFrame(frame);
  </script>
</body>
</html>
